import{_ as l,W as i,X as p,Y as c,$ as n,a0 as s,Z as e,a1 as t,D as o}from"./framework-f38b131a.js";const r={},d=t('<h1 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h1><p>Frp是一个高性能的内网穿透反向代理应用，可以将内网服务访问端口映射到公网机器指定端口上，这样便可以在公网环境下访问到内网的服务,包括但不限于：</p><ul><li>各类web服务(个人网站、文件共享等)</li><li>SSH</li><li>远程桌面</li><li>...</li></ul><p>通过它，你可以自由访问家中的电脑、路由器、摄像头等各种设备。</p><h1 id="基本原理" tabindex="-1"><a class="header-anchor" href="#基本原理" aria-hidden="true">#</a> 基本原理</h1><p>如下是frp的基本原理图，其中下方的虚线框是位于内网机器上的各类服务，中间的椭圆框是拥有公网IP的机器，上方的圆角矩形框是位于公网环境下的普通用户。可以看到，用户能够访问到内网服务都是要通过中间的公网机器中转来实现的。</p><figure><img src="https://blog.kevin2li.top/static/img/530fc52d6aed332e6c281b8cdc6f9187.20221019102104.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>',7),u=n("h1",{id:"安装",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#安装","aria-hidden":"true"},"#"),s(" 安装")],-1),v={href:"https://github.com/fatedier/frp",target:"_blank",rel:"noopener noreferrer"},m={href:"https://github.com/fatedier/frp/releases",target:"_blank",rel:"noopener noreferrer"},k=t(`<figure><img src="https://blog.kevin2li.top/static/img/922ccfe1b121efcb8ecaaa118ca704cb.20221019103417.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>我选用的是<code>linux_amd64</code>平台的, 可以通过下面命令下载：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">wget</span> https://github.com/fatedier/frp/releases/download/v0.44.0/frp_0.44.0_linux_amd64.tar.gz
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>注意: 在内网机器和公网机器上都需要下载frp安装包</p><ol start="2"><li>解压下载的压缩包<br> 可以看到里面包含如下内容：</li></ol><figure><img src="https://blog.kevin2li.top/static/img/4466daf6df51f4c94d56acf0434bbd9b.20221019123139.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>一共7个文件，可分为三组：</p><p>内网机器上使用：</p><ul><li>fprc: frp客户端可执行文件</li><li>frpc.ini：frpc的配置文件，内网机器上各种内网穿透服务的设置都是修改这个文件控制的</li><li>frpc_full.ini：frpc的完整配置文件</li></ul><p>公网机器上使用：</p><ul><li>frps：frp服务端可执行文件</li><li>frps.ini：frps的配置文件</li><li>frps_full.ini：frps的完整配置文件</li></ul><p>许可证文件：</p><ul><li>License：使用Apache许可证</li></ul><h1 id="基本使用" tabindex="-1"><a class="header-anchor" href="#基本使用" aria-hidden="true">#</a> 基本使用</h1><p>下面以一个具体场景为例来说明frp的使用方法。</p><div class="hint-container info"><p class="hint-container-title">假设场景</p><p>我在内网上有多台机器A，B，C，有一台公网机器D，其公网IP为<code>x.x.x.x</code>，现在我在内网机器A上新开了一个web服务，取名叫<code>my_web_service</code>, 访问端口为8000，如何使其可通过公网访问？</p></div><p><strong>使用方法：</strong></p><ol><li>内网机器A上的设置：<br> 首先查看一下当前默认的<code>frpc.ini</code>的配置：</li></ol><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">common</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">server_addr</span> <span class="token punctuation">=</span> <span class="token value attr-value">127.0.0.1</span>
<span class="token key attr-name">server_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">7000</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">ssh</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">type</span> <span class="token punctuation">=</span> <span class="token value attr-value">tcp</span>
<span class="token key attr-name">local_ip</span> <span class="token punctuation">=</span> <span class="token value attr-value">127.0.0.1</span>
<span class="token key attr-name">local_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">22</span>
<span class="token key attr-name">remote_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">6000</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中<code>common.server_addr</code>表示需要改为自己的公网机器的IP: <code>x.x.x.x</code>，</p><div class="hint-container tip"><p class="hint-container-title">提示</p><p><code>common.server_addr</code>是frps与frpc程序之间通信的端口，如果为了更安全，也可以改为其他高端口，服务端frps.ini也要同步修改，无所谓的话可以直接忽略。</p></div><p>默认的配置文件中自带了一个<code>ssh</code>的内网穿透服务，其表示将内网机器的22端口(ssh应用默认端口)映射到公网机器的6000端口。</p><p>现在为了添加自己的其他服务，我们在<code>frpc.ini</code>文件尾部再新增一个配置项，内容如下：</p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">my_web_service</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">type</span> <span class="token punctuation">=</span> <span class="token value attr-value">tcp</span>
<span class="token key attr-name">local_ip</span> <span class="token punctuation">=</span> <span class="token value attr-value">127.0.0.1</span>
<span class="token key attr-name">local_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">8000  # 内网机器服务访问端口</span>
<span class="token key attr-name">remote_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">8000 # 映射到公网机器的端口</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>目前完整的<code>frpc.ini</code>文件内容如下：</p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">common</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">server_addr</span> <span class="token punctuation">=</span> <span class="token value attr-value">x.x.x.x # 公网IP地址</span>
<span class="token key attr-name">server_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">7000</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">ssh</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">type</span> <span class="token punctuation">=</span> <span class="token value attr-value">tcp</span>
<span class="token key attr-name">local_ip</span> <span class="token punctuation">=</span> <span class="token value attr-value">127.0.0.1</span>
<span class="token key attr-name">local_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">22</span>
<span class="token key attr-name">remote_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">6000</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">my_web_service</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">type</span> <span class="token punctuation">=</span> <span class="token value attr-value">tcp</span>
<span class="token key attr-name">local_ip</span> <span class="token punctuation">=</span> <span class="token value attr-value">127.0.0.1</span>
<span class="token key attr-name">local_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">8000  # 内网机器服务访问端口</span>
<span class="token key attr-name">remote_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">8000 # 映射到公网机器的端口</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container warning"><p class="hint-container-title">注意</p><p>这里设置的<code>server_port</code>和所有服务的<code>remote_port</code>都要在公网机器上保持开放状态，否则会导致连接失败。 (如果觉得在服务器上开放太多端口不安全，后面可以使用nginx等工具设置反向代理,这样公网服务器只需暴露少数几个常用入口端口即可)</p></div><ol start="2"><li>公网机器D上的设置：</li></ol><ul><li><strong>确保云服务器安全组策略里开放了相应端口</strong><br> 不同云服务器厂商设置可能不太一样，下面是我用的腾讯云服务器的示例：</li></ul><figure><img src="https://blog.kevin2li.top/static/img/8c0ae72c2a98a176eb9cbd8b2be82f80.20221019110457.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>因为我在服务器上另外装了防火墙，所以这里允许所有的流量进入。</p><ul><li><strong>确保防火墙开放了相应端口</strong><br> 防火墙管理相关命令：</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 安装防火墙</span>
<span class="token function">sudo</span> <span class="token function">apt</span> update
<span class="token function">sudo</span> <span class="token function">apt</span> <span class="token function">install</span> firewalld

<span class="token comment"># 查看已开放端口</span>
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --list-ports

<span class="token comment"># 添加端口</span>
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port <span class="token number">8000</span>/tcp

<span class="token comment"># 移除端口</span>
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --remove-port <span class="token number">8000</span>/tcp
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>大家核对下自己映射到公网服务器的端口是否处于放行状态，没有的话按照上面的命令添加一下。</p><ul><li>修改配置文件</li></ul><p>首先查看一下当前默认的<code>frps.ini</code></p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">common</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">bind_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">7000</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>增加管理后台：</p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">common</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">bind_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">7000</span>

<span class="token key attr-name">dashboard_port</span> <span class="token punctuation">=</span> <span class="token value attr-value">9000 # dashboard访问端口</span>
<span class="token key attr-name">dashboard_user</span> <span class="token punctuation">=</span> <span class="token value attr-value">admin</span>
<span class="token key attr-name">dashboard_pwd</span> <span class="token punctuation">=</span> <span class="token value attr-value">admin</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>测试</li></ol><p>先启动frps，再启动frpc。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 公网机器(在frp安装目录下执行)</span>
./frps <span class="token parameter variable">-c</span> frps.ini

<span class="token comment"># 内网机器(在frp安装目录下执行)</span>
./frpc <span class="token parameter variable">-c</span> frpc.ini
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果顺利的话，现在应该能够通过<code>x.x.x.x:8000</code>访问内网机器上的服务了 举例：</p><ul><li>如果你的服务是web: 浏览器访问<code>x.x.x.x:8000</code>应该能打开对应的网页</li><li>如果你的服务是ssh： 可以通过下面命令连接上内网机器</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ssh</span> <span class="token parameter variable">-oPort</span><span class="token operator">=</span><span class="token number">6000</span> username@x.x.x.x
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>如果你的服务是微软远程桌面： 你可以这样连接:</li></ul><figure><img src="https://blog.kevin2li.top/static/img/baba663ee3fc3ea8f293dfb8626ded0c.20221019135553.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li>... 你还可以访问<code>x.x.x.x:9000</code>来查看所有内网穿透服务的连接状态等信息</li></ul><figure><img src="https://blog.kevin2li.top/static/img/b566f75561af8bf1abac25e33b73bb88.20221019133335.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="4"><li>后台运行<br> 为了让程序一直挂在后台运行，可以使用<code>nohup</code>命令，不过更推荐的做法是下面章节介绍的服务化，更方便管理。</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># frpc</span>
<span class="token function">nohup</span> ./frpc <span class="token parameter variable">-c</span> frpc.ini <span class="token operator">&gt;</span>frpc.log <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span><span class="token file-descriptor important">&amp;1</span> <span class="token operator">&amp;</span>

<span class="token comment"># frps</span>
<span class="token function">nohup</span> ./frps <span class="token parameter variable">-c</span> frps.ini <span class="token operator">&gt;</span>frps.log <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span><span class="token file-descriptor important">&amp;1</span> <span class="token operator">&amp;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="进阶使用" tabindex="-1"><a class="header-anchor" href="#进阶使用" aria-hidden="true">#</a> 进阶使用</h1><h2 id="服务化" tabindex="-1"><a class="header-anchor" href="#服务化" aria-hidden="true">#</a> 服务化</h2><p>为了方便frp应用的管理，将其编写为系统服务，方便管理状态(启动、停止、开机自启等)。</p><h3 id="客户端服务配置" tabindex="-1"><a class="header-anchor" href="#客户端服务配置" aria-hidden="true">#</a> 客户端服务配置</h3><p>编写如下两个文件，将<code>&lt;your_frp_dir&gt;</code>替换为你的frp绝对安装路径。</p><ol><li><code>/etc/systemd/system/frpc.service</code></li></ol><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">Unit</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">Description</span><span class="token punctuation">=</span><span class="token value attr-value">frpc service</span>
<span class="token key attr-name">After</span><span class="token punctuation">=</span><span class="token value attr-value">network.service</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">Service</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">Type</span><span class="token punctuation">=</span><span class="token value attr-value">simple</span>
<span class="token key attr-name">User</span><span class="token punctuation">=</span><span class="token value attr-value">root</span>
<span class="token key attr-name">Group</span><span class="token punctuation">=</span><span class="token value attr-value">root</span>
<span class="token key attr-name">WorkingDirectory</span><span class="token punctuation">=</span><span class="token value attr-value">/root</span>
<span class="token key attr-name">ExecStart</span><span class="token punctuation">=</span><span class="token value attr-value">sh &lt;your_frp_dir&gt;/frpc_start.sh</span>
<span class="token key attr-name">PrivateTmp</span><span class="token punctuation">=</span><span class="token value attr-value">true</span>
<span class="token key attr-name">Restart</span><span class="token punctuation">=</span><span class="token value attr-value">on-failure</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">Install</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">WantedBy</span><span class="token punctuation">=</span><span class="token value attr-value">multi-user.target</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li><code>&lt;your_frp_dir&gt;/frpc_start.sh</code>:</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> <span class="token operator">&lt;</span>your_frp_dir<span class="token operator">&gt;</span>
./frpc <span class="token parameter variable">-c</span> frpc.ini <span class="token operator">&gt;</span>frps.log <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span><span class="token file-descriptor important">&amp;1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>frpc服务管理：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 重新加载服务(每次添加新服务后，都要先执行下此命令)</span>
<span class="token function">sudo</span> systemctl daemon-reload
<span class="token comment"># 启动</span>
<span class="token function">sudo</span> systemctl start frpc
<span class="token comment"># 停止</span>
<span class="token function">sudo</span> systemctl stop frpc
<span class="token comment"># 查看状态</span>
<span class="token function">sudo</span> systemctl status frpc
<span class="token comment"># 设置开机自启</span>
<span class="token function">sudo</span> systemctl <span class="token builtin class-name">enable</span> frpc
<span class="token comment"># 取消开机自启</span>
<span class="token function">sudo</span> systemctl disable frpc
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="服务端服务配置" tabindex="-1"><a class="header-anchor" href="#服务端服务配置" aria-hidden="true">#</a> 服务端服务配置</h3><p>编写如下两个文件，将<code>&lt;your_frp_dir&gt;</code>替换为你的frp绝对安装路径。</p><ol><li><code>/etc/systemd/system/frps.service</code></li></ol><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">Unit</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">Description</span><span class="token punctuation">=</span><span class="token value attr-value">frps service</span>
<span class="token key attr-name">After</span><span class="token punctuation">=</span><span class="token value attr-value">network.service</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">Service</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">Type</span><span class="token punctuation">=</span><span class="token value attr-value">simple</span>
<span class="token key attr-name">User</span><span class="token punctuation">=</span><span class="token value attr-value">root</span>
<span class="token key attr-name">Group</span><span class="token punctuation">=</span><span class="token value attr-value">root</span>
<span class="token key attr-name">WorkingDirectory</span><span class="token punctuation">=</span><span class="token value attr-value">/root</span>
<span class="token key attr-name">ExecStart</span><span class="token punctuation">=</span><span class="token value attr-value">sh &lt;your_frp_dir&gt;/frps_start.sh</span>
<span class="token key attr-name">PrivateTmp</span><span class="token punctuation">=</span><span class="token value attr-value">true</span>
<span class="token key attr-name">Restart</span><span class="token punctuation">=</span><span class="token value attr-value">on-failure</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">Install</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">WantedBy</span><span class="token punctuation">=</span><span class="token value attr-value">multi-user.target</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li><code>&lt;your_frp_dir&gt;/frps_start.sh</code></li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> <span class="token operator">&lt;</span>your_frp_dir<span class="token operator">&gt;</span>
./frps <span class="token parameter variable">-c</span> frps.ini <span class="token operator">&gt;</span>frps.log <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span><span class="token file-descriptor important">&amp;1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>frps服务管理：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 重新加载服务(每次添加新服务后，都要先执行下此命令)</span>
<span class="token function">sudo</span> systemctl daemon-reload
<span class="token comment"># 启动</span>
<span class="token function">sudo</span> systemctl start frps
<span class="token comment"># 停止</span>
<span class="token function">sudo</span> systemctl stop frps
<span class="token comment"># 查看状态</span>
<span class="token function">sudo</span> systemctl status frps
<span class="token comment"># 设置开机自启</span>
<span class="token function">sudo</span> systemctl <span class="token builtin class-name">enable</span> frps
<span class="token comment"># 取消开机自启</span>
<span class="token function">sudo</span> systemctl disable frps
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="域名访问" tabindex="-1"><a class="header-anchor" href="#域名访问" aria-hidden="true">#</a> 域名访问</h2><p>当设置的内网穿透应用逐渐增多后，每次访问不同的服务都要输入公网IP和对应的端口号，感觉不是太方便，也不太优雅。由于没有设置https，安全性也没有保证。综合考虑，决定给不同的应用分配一个域名，并升级为https来解决上面的问题。关于这部分内容下期再介绍。</p>`,72);function b(f,g){const a=o("ExternalLinkIcon");return i(),p("div",null,[d,c(" more "),u,n("p",null,[s("项目地址："),n("a",v,[s("https://github.com/fatedier/frp"),e(a)])]),n("ol",null,[n("li",null,[s("首先去项目"),n("a",m,[s("Release"),e(a)]),s("版块下载适合自己平台的最新的安装包, 当前的最新版是0.44。")])]),k])}const _=l(r,[["render",b],["__file","内网穿透工具——Frp安装与使用教程.html.vue"]]);export{_ as default};
